/**
 * declarations.d.ts
 * Global type declarations for the project.
 * Fixes TypeScript errors for SVG file imports.
 */

// SVG files — imported as React components via react-native-svg-transformer
declare module '*.svg' {
  import React from 'react';
  import { SvgProps } from 'react-native-svg';
  const content: React.FC<SvgProps>;
  export default content;
}

// PNG / JPG / image assets
declare module '*.png' {
  const value: number;
  export default value;
}

declare module '*.jpg' {
  const value: number;
  export default value;
}

declare module '*.jpeg' {
  const value: number;
  export default value;
}

declare module '*.gif' {
  const value: number;
  export default value;
}

declare module '*.webp' {
  const value: number;
  export default value;
}